import { Component, signal, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatSelectModule } from '@angular/material/select';
import { MatDatepickerModule } from '@angular/material/datepicker';
import { MatNativeDateModule } from '@angular/material/core';
import { MatButtonModule } from '@angular/material/button';

@Component({
  selector: 'app-ticket-details',
  imports: [
    CommonModule,
    FormsModule,
    MatFormFieldModule,
    MatInputModule,
    MatSelectModule,
    MatDatepickerModule,
    MatNativeDateModule,
    MatButtonModule,
  ],
  templateUrl: './ticket-details.html',
  styleUrl: './ticket-details.scss',
})
export class TicketDetails {
  title = signal('');
  description = signal('');
  date = signal<Date | null>(null);
  category = signal('general');

  categories = ['general', 'transport', 'event', 'other'];

  valid = computed(() => !!this.title().trim() && !!this.date());

  submit() {
    if (!this.valid()) return;
    const payload = {
      title: this.title(),
      description: this.description(),
      date: this.date(),
      category: this.category(),
    };
    // TODO: send payload to service
    console.log('Ticket submitted', payload);
  }
}

:host {
	display: block;
	padding: 16px;
}
.ticket-form {
	display: grid;
	gap: 12px;
	grid-template-columns: 1fr;
	max-width: 600px;
}
.ticket-form .full { grid-column: 1 / -1; }
.actions { display:flex; justify-content:flex-end; margin-top:8px }

import { Component, signal } from '@angular/core';
import { RouterOutlet } from '@angular/router';
import { TicketDetails } from './ticket-details/ticket-details';

@Component({
  selector: 'app-root',
  imports: [RouterOutlet, TicketDetails],
  templateUrl: './app.html',
  styleUrl: './app.scss'
})
export class App {
  protected readonly title = signal('citypass-ai');
}

